@namespace sv_0bd10bbbf29d4b829f0521f9615286de.Components.Pages.Apply

<nav class="mb-4">
    <div class="d-flex justify-content-between position-relative">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var isCurrent = step == CurrentStep;
            var isCompleted = step < CurrentStep;
            var isFuture = step > CurrentStep;

            <div class="text-center flex-fill" style="z-index: 1;">
                <button type="button"
                        class="btn rounded-circle d-inline-flex align-items-center justify-content-center @StepButtonClass(step)"
                        style="width: 40px; height: 40px; font-size: 0.85rem;"
                        disabled="@isFuture"
                        @onclick="() => OnStepClicked.InvokeAsync(step)">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        @(step + 1)
                    }
                </button>
                <div class="small mt-1 @(isFuture ? "text-muted" : (isCurrent ? "fw-bold" : ""))">
                    @StepNames[step]
                </div>
            </div>
        }
    </div>
</nav>

@code {
    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string StepButtonClass(int step)
    {
        if (step == CurrentStep) return "btn-primary";
        if (step < CurrentStep) return "btn-success";
        return "btn-outline-secondary";
    }
}

@namespace sv_0bd10bbbf29d4b829f0521f9615286de.Components.Pages.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @Index</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name</label>
                <input class="form-control" value="@Company" @onchange="e => { Company = (string?)e.Value ?? ""; NotifyChanged(); }" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title</label>
                <input class="form-control" value="@Title" @onchange="e => { Title = (string?)e.Value ?? ""; NotifyChanged(); }" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date</label>
                <input type="date" class="form-control" value="@StartDate.ToString("yyyy-MM-dd")"
                       @onchange="e => { StartDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")); NotifyChanged(); }" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@(EndDate?.ToString("yyyy-MM-dd") ?? "")"
                       disabled="@IsCurrent"
                       @onchange="e => { EndDate = string.IsNullOrEmpty((string?)e.Value) ? null : DateTime.Parse((string)e.Value); NotifyChanged(); }" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"current-{Index}")" checked="@IsCurrent"
                           @onchange="e => { IsCurrent = (bool)(e.Value ?? false); if (IsCurrent) EndDate = null; NotifyChanged(); }" />
                    <label class="form-check-label" for="@($"current-{Index}")">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Description"
                          @onchange="e => { Description = (string?)e.Value ?? ""; NotifyChanged(); }"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public int Index { get; set; }
    [Parameter] public string Company { get; set; } = "";
    [Parameter] public string Title { get; set; } = "";
    [Parameter] public DateTime StartDate { get; set; } = DateTime.Today;
    [Parameter] public DateTime? EndDate { get; set; }
    [Parameter] public bool IsCurrent { get; set; }
    [Parameter] public string Description { get; set; } = "";
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public EventCallback<WorkEntryData> OnChanged { get; set; }

    private void NotifyChanged()
    {
        OnChanged.InvokeAsync(new WorkEntryData(Company, Title, StartDate, IsCurrent ? null : EndDate, Description));
    }

    public record WorkEntryData(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
}

