@namespace sv_0bd10bbbf29d4b829f0521f9615286de.Components.Pages.Apply

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control" value="@FullName" @onchange="e => FullName = (string?)e.Value ?? """ />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(emailInvalid ? "is-invalid" : "")" value="@Email"
               @onchange="e => { Email = (string?)e.Value ?? ""; emailInvalid = false; }" />
        @if (emailInvalid)
        {
            <div class="invalid-feedback">Please enter a valid email address.</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" value="@Phone" @onchange="e => Phone = (string?)e.Value ?? """ />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control" value="@Address" @onchange="e => Address = (string?)e.Value ?? """ />
    </div>
