    {
        Entries[index] = new EntryModel
        {
            Company = data.Company,
            Title = data.Title,
            StartDate = data.StartDate,
            EndDate = data.EndDate,
            Description = data.Description
        };
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (Entries.Any(e => string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title)))
        {
            ErrorMessage = "Each position requires at least a company name and job title.";
            return;
        }

        await OnNext.InvokeAsync(Entries);
    }

    public class EntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; }
        public string Description { get; set; } = "";
    }
}
