+    [Parameter] public EventCallback<PersonalInfoResult> OnNext { get; set; }
+    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }
+
+    private string? ErrorMessage;
+    private bool emailInvalid;
+    private bool isValidating;
+
+    private async Task HandleNext()
+    {
+        ErrorMessage = null;
+        emailInvalid = false;
+
+        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
+            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
+        {
+            ErrorMessage = "All fields are required.";
+            return;
+        }
+
+        if (ValidateEmail is not null)
+        {
+            isValidating = true;
+            StateHasChanged();
+            var valid = await ValidateEmail(Email);
+            isValidating = false;
+
+            if (!valid)
+            {
+                emailInvalid = true;
+                return;
+            }
+        }
+
+        await OnNext.InvokeAsync(new PersonalInfoResult(FullName, Email, Phone, Address));
+    }
+
+    public record PersonalInfoResult(string FullName, string Email, string Phone, string Address);
+}
+

