@page "/apply"
@using sv_0bd10bbbf29d4b829f0521f9615286de.Components.Pages.Apply
@using sv_0bd10bbbf29d4b829f0521f9615286de.Models
@rendermode InteractiveServer
@inject IApplicationService AppService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="@currentStep" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep FullName="@personalFullName"
                              Email="@personalEmail"
                              Phone="@personalPhone"
                              Address="@personalAddress"
                              ValidateEmail="AppService.ValidateEmailAsync"
                              OnNext="HandlePersonalNext" />
            break;

        case 1:
            <WorkHistoryStep Entries="@workEntries"
                             OnNext="HandleWorkNext"
                             OnBack="GoBack" />
            break;

        case 2:
            <ReferencesStep References="@references"
                            OnNext="HandleReferencesNext"
                            OnBack="GoBack" />
            break;

        case 3:
            <CoverLetterStep CoverLetter="@coverLetter"
                             OnCoverLetterChanged="val => coverLetter = val"
                             OnNext="() => GoToStep(4)"
                             OnBack="GoBack" />
            break;

        case 4:
            <ReviewStep Personal="@BuildPersonalInfo()"
                        WorkEntries="@BuildWorkEntries()"
                        References="@BuildReferences()"
                        CoverLetter="@coverLetter"
                        OnEditSection="GoToStep"
                        OnBack="GoBack"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep;

    // Step 1 state
    private string personalFullName = "";
    private string personalEmail = "";
    private string personalPhone = "";
    private string personalAddress = "";

    // Step 2 state
    private List<WorkHistoryStep.EntryModel> workEntries = new() { new() };

    // Step 3 state
    private List<ReferencesStep.RefModel> references = new() { new(), new() };

    // Step 4 state
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        if (step <= currentStep)
        {
            currentStep = step;
        }
    }

    private void GoBack()
    {
        if (currentStep > 0) currentStep--;
    }

    private void HandlePersonalNext(PersonalInfoStep.PersonalInfoResult result)
    {
        personalFullName = result.FullName;
        personalEmail = result.Email;
        personalPhone = result.Phone;
        personalAddress = result.Address;
        currentStep = 1;
    }

    private void HandleWorkNext(List<WorkHistoryStep.EntryModel> entries)
    {
        workEntries = entries;
        currentStep = 2;
    }

    private void HandleReferencesNext(List<ReferencesStep.RefModel> refs)
    {
        references = refs;
        currentStep = 3;
    }

    private PersonalInfo BuildPersonalInfo() =>
        new(personalFullName, personalEmail, personalPhone, personalAddress);

    private List<WorkEntry> BuildWorkEntries() =>
        workEntries.Select(e => new WorkEntry(e.Company, e.Title, e.StartDate, e.EndDate, e.Description)).ToList();

    private List<Reference> BuildReferences() =>
        references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();

    private async Task<int> SubmitApplication()
    {
        var application = new JobApplication(BuildPersonalInfo(), new WorkHistory(BuildWorkEntries()), BuildReferences(), coverLetter);
        return await AppService.SubmitApplicationAsync(application);
    }
}

