1. @namespace sv_0bd10bbbf29d4b829f0521f9615286de.Components.Pages.Apply
2. 
3. <h4 class="mb-3">Personal Information</h4>
4. 
5. @if (!string.IsNullOrEmpty(ErrorMessage))
6. {
7.     <div class="alert alert-danger">@ErrorMessage</div>
8. }
9. 
10. <div class="row g-3">
11.     <div class="col-md-6">
12.         <label class="form-label">Full Name <span class="text-danger">*</span></label>
13.         <input class="form-control" value="@FullName" @onchange="e => FullName = (string?)e.Value ?? """ />
14.     </div>
15.     <div class="col-md-6">
16.         <label class="form-label">Email <span class="text-danger">*</span></label>
17.         <input type="email" class="form-control @(emailInvalid ? "is-invalid" : "")" value="@Email"
18.                @onchange="e => { Email = (string?)e.Value ?? ""; emailInvalid = false; }" />
19.         @if (emailInvalid)
20.         {
21.             <div class="invalid-feedback">Please enter a valid email address.</div>
22.         }
23.     </div>
24.     <div class="col-md-6">
25.         <label class="form-label">Phone <span class="text-danger">*</span></label>
26.         <input type="tel" class="form-control" value="@Phone" @onchange="e => Phone = (string?)e.Value ?? """ />
27.     </div>
28.     <div class="col-md-6">
29.         <label class="form-label">Address <span class="text-danger">*</span></label>
30.         <input class="form-control" value="@Address" @onchange="e => Address = (string?)e.Value ?? """ />
31.     </div>
32. </div>
33. 
34. <div class="d-flex justify-content-end mt-4">
35.     <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
36.         @if (isValidating)
37.         {
38.             <span class="spinner-border spinner-border-sm me-1"></span>
39.         }
40.         Next
41.     </button>
42. </div>
43. 
44. @code {
45.     [Parameter] public string FullName { get; set; } = "";
46.     [Parameter] public string Email { get; set; } = "";
47.     [Parameter] public string Phone { get; set; } = "";
48.     [Parameter] public string Address { get; set; } = "";
49.     [Parameter] public EventCallback<PersonalInfoResult> OnNext { get; set; }
50.     [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }
51. 
52.     private string? ErrorMessage;
53.     private bool emailInvalid;
54.     private bool isValidating;
55. 
56.     private async Task HandleNext()
57.     {
58.         ErrorMessage = null;
59.         emailInvalid = false;
60. 
61.         if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
62.             || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
63.         {
64.             ErrorMessage = "All fields are required.";
65.             return;
66.         }
67. 
68.         if (ValidateEmail is not null)
69.         {
70.             isValidating = true;
71.             StateHasChanged();
72.             var valid = await ValidateEmail(Email);
73.             isValidating = false;
74. 
75.             if (!valid)
76.             {
77.                 emailInvalid = true;
78.                 return;
79.             }
80.         }
81. 
82.         await OnNext.InvokeAsync(new PersonalInfoResult(FullName, Email, Phone, Address));
83.     }
84. 
85.     public record PersonalInfoResult(string FullName, string Email, string Phone, string Address);
86. }
