 <h4 class="mb-3">Personal Information</h4>

 @if (!string.IsNullOrEmpty(ErrorMessage))
 {
     <div class="alert alert-danger">@ErrorMessage</div>
 }

 <div class="row g-3">
     <div class="col-md-6">
         <label class="form-label">Full Name <span class="text-danger">*</span></label>
         <input class="form-control" value="@FullName" @onchange="e => FullName = (string?)e.Value ?? """ />
     </div>
     <div class="col-md-6">
         <label class="form-label">Email <span class="text-danger">*</span></label>
         <input type="email" class="form-control @(emailInvalid ? "is-invalid" : "")" value="@Email"
                @onchange="e => { Email = (string?)e.Value ?? ""; emailInvalid = false; }" />
         @if (emailInvalid)
         {
             <div class="invalid-feedback">Please enter a valid email address.</div>
         }
     </div>
     <div class="col-md-6">
         <label class="form-label">Phone <span class="text-danger">*</span></label>
         <input type="tel" class="form-control" value="@Phone" @onchange="e => Phone = (string?)e.Value ?? """ />
     </div>
     <div class="col-md-6">
         <label class="form-label">Address <span class="text-danger">*</span></label>
         <input class="form-control" value="@Address" @onchange="e => Address = (string?)e.Value ?? """ />
     </div>
 </div>

 <div class="d-flex justify-content-end mt-4">
     <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
         @if (isValidating)
         {
             <span class="spinner-border spinner-border-sm me-1"></span>
         }
         Next
     </button>
 </div>

 @code {
     [Parameter] public string FullName { get; set; } = "";
     [Parameter] public string Email { get; set; } = "";
     [Parameter] public string Phone { get; set; } = "";
     [Parameter] public string Address { get; set; } = "";
     [Parameter] public EventCallback<PersonalInfoResult> OnNext { get; set; }
     [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

     private string? ErrorMessage;
     private bool emailInvalid;
     private bool isValidating;

     private async Task HandleNext()
     {
         ErrorMessage = null;
         emailInvalid = false;

         if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
             || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
         {
             ErrorMessage = "All fields are required.";
             return;
         }

         if (ValidateEmail is not null)
         {
             isValidating = true;
             StateHasChanged();
             var valid = await ValidateEmail(Email);
             isValidating = false;

             if (!valid)
             {
                 emailInvalid = true;
                 return;
             }
         }

         await OnNext.InvokeAsync(new PersonalInfoResult(FullName, Email, Phone, Address));
     }

     public record PersonalInfoResult(string FullName, string Email, string Phone, string Address);
 }

